// Generated by Liminal ParticleSystem
// Particle Count: 100

// Seed: 43292298

let particles = [];

function setup() {
  createCanvas(600, 400);
  // RGB color mode
  colorMode(RGB);

  // Initialize particles
  for (let i = 0; i < 100; i++) {
    particles.push(new Particle());
  }
}

function draw() {
  background(0);

  // Update and display particles
  for (let i = particles.length - 1; i >= 0; i--) {
    particles[i].update();
    particles[i].display();

    // Remove dead particles
    if (particles[i].lifespan < 1) {
      particles.splice(i, 1);
    }
  }

  
}

class Particle {
  constructor() {
    this.x = random(width);
    this.y = random(height);
    this.vx = random(-2, 2);
    this.vy = random(-2, 2);
    this.size = random(2, 8);
    this.lifespan = 255;
    // RGB full spectrum
this.baseColor = color(random(255), random(255), random(255));

  }

  update() {
    

    // Apply velocity
    this.x += this.vx;
    this.y += this.vy;

    // Wrap around edges
    if (this.x < 0) this.x = width;
    if (this.x > width) this.x = 0;
    if (this.y < 0) this.y = height;
    if (this.y > height) this.y = 0;

    // Apply decay
    this.lifespan *= 0.98;

    // Update color based on velocity
    let speed = sqrt(this.vx * this.vx + this.vy * this.vy);
    let colorRatio = constrain(speed / 4, 0, 1);
    this.color = lerpColor(
      color(255, 100, 100),
      color(100, 100, 255),
      colorRatio
    );
  }

  display() {
    noStroke();
    fill(this.color, this.lifespan);
    ellipse(this.x, this.y, this.size);
  }

  
}